using System.ComponentModel;
using System.Text.Json;
using Microsoft.Extensions.Logging;
using ModelContextProtocol.Server;

namespace ApiMcpServer;

/// <summary>
/// MCP tools that wrap a REST API via HttpClient.
/// Non-static class — HttpClient and ILogger are injected via the constructor.
/// </summary>
[McpServerToolType]
public class ApiTools(HttpClient httpClient, ILogger<ApiTools> logger)
{
    private static readonly JsonSerializerOptions JsonOptions = new() { WriteIndented = true };

    [McpServerTool(ReadOnly = true), Description("Get a user by ID from the REST API.")]
    public async Task<string> GetUser(
        [Description("The numeric user ID to look up")] int userId,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching user {UserId}", userId);

        var response = await httpClient.GetAsync($"/users/{userId}", cancellationToken);
        response.EnsureSuccessStatusCode();

        var json = await response.Content.ReadAsStringAsync(cancellationToken);
        return json;
    }

    [McpServerTool(ReadOnly = true), Description("Search for users by name. Returns a JSON array of matching users.")]
    public async Task<string> SearchUsers(
        [Description("Name or partial name to search for")] string query,
        [Description("Maximum number of results to return (1-100, default 10)")] int limit = 10,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Searching users with query '{Query}', limit {Limit}", query, limit);

        limit = Math.Clamp(limit, 1, 100);
        var response = await httpClient.GetAsync($"/users?name={Uri.EscapeDataString(query)}&limit={limit}", cancellationToken);
        response.EnsureSuccessStatusCode();

        var json = await response.Content.ReadAsStringAsync(cancellationToken);
        return json;
    }

    [McpServerTool, Description("Create a new user. Returns the created user as JSON.")]
    public async Task<string> CreateUser(
        [Description("The user's full name")] string name,
        [Description("The user's email address")] string email,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Creating user {Name} <{Email}>", name, email);

        var payload = JsonSerializer.Serialize(new { name, email }, JsonOptions);
        var content = new StringContent(payload, System.Text.Encoding.UTF8, "application/json");

        var response = await httpClient.PostAsync("/users", content, cancellationToken);
        response.EnsureSuccessStatusCode();

        var json = await response.Content.ReadAsStringAsync(cancellationToken);
        return json;
    }
}

